namespace CourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = "";
    public string Title { get; set; } = "";
    public string Description { get; set; } = "";
    public int Credits { get; set; }
    public string Schedule { get; set; } = "";
    public string Location { get; set; } = "";
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = "";
    public Instructor Instructor { get; set; } = new();
    public bool IsFeatured { get; set; }
}

namespace CourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Abbreviation { get; set; } = "";
    public string Description { get; set; } = "";
    public int CourseCount { get; set; }
}

namespace CourseCatalog.Models;

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Title { get; set; } = "";
    public string Email { get; set; } = "";
    public string Bio { get; set; } = "";
    public string OfficeHours { get; set; } = "";
    public string Office { get; set; } = "";
}

using System.ComponentModel.DataAnnotations;

namespace CourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = "";

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z]{2}\d{6}$", ErrorMessage = "Student ID must be 2 letters followed by 6 digits (e.g., CS123456).")]
    public string StudentId { get; set; } = "";

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }

    [StringLength(500)]
    public string Notes { get; set; } = "";
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Abbreviation = "CS", Description = "Study of computation, algorithms, and information systems.", CourseCount = 4 },
            new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH", Description = "Study of numbers, structures, and patterns.", CourseCount = 3 },
            new() { Id = 3, Name = "Physics", Abbreviation = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature.", CourseCount = 3 },
            new() { Id = 4, Name = "English", Abbreviation = "ENG", Description = "Study of literature, writing, and language.", CourseCount = 2 },
            new() { Id = 5, Name = "History", Abbreviation = "HIST", Description = "Study of past events, societies, and civilizations.", CourseCount = 2 },
        };

        var instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Ada Chen", Title = "Professor", Email = "achen@university.edu", Bio = "Dr. Chen specializes in algorithms and data structures with 15 years of teaching experience. She has published over 40 papers in top CS conferences.", OfficeHours = "Mon/Wed 2:00–4:00 PM", Office = "Science Hall 301" },
            new() { Id = 2, Name = "Dr. James Martinez", Title = "Associate Professor", Email = "jmartinez@university.edu", Bio = "Dr. Martinez researches machine learning and artificial intelligence. He previously worked at a leading tech company for 8 years.", OfficeHours = "Tue/Thu 1:00–3:00 PM", Office = "Science Hall 312" },
            new() { Id = 3, Name = "Dr. Sarah Okonkwo", Title = "Professor", Email = "sokonkwo@university.edu", Bio = "Dr. Okonkwo is an expert in abstract algebra and number theory. She is the recipient of the University Distinguished Teaching Award.", OfficeHours = "Mon/Wed 10:00 AM–12:00 PM", Office = "Math Building 205" },
            new() { Id = 4, Name = "Dr. Robert Liu", Title = "Assistant Professor", Email = "rliu@university.edu", Bio = "Dr. Liu focuses on quantum mechanics and particle physics. He completed his postdoc at CERN.", OfficeHours = "Wed/Fri 3:00–5:00 PM", Office = "Physics Lab 108" },
            new() { Id = 5, Name = "Prof. Emily Carter", Title = "Senior Lecturer", Email = "ecarter@university.edu", Bio = "Prof. Carter is a published novelist and literary critic with expertise in modern American fiction.", OfficeHours = "Tue/Thu 11:00 AM–1:00 PM", Office = "Humanities 402" },
            new() { Id = 6, Name = "Dr. Michael Torres", Title = "Professor", Email = "mtorres@university.edu", Bio = "Dr. Torres is a specialist in medieval European history and has led archaeological digs across Southern Europe.", OfficeHours = "Mon/Fri 9:00–11:00 AM", Office = "Humanities 310" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, CourseCode = "CS 101", Title = "Introduction to Computer Science", Description = "Foundational course covering programming basics, problem solving, and computational thinking using Python.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Hall 120", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[0], IsFeatured = true },
            new() { Id = 2, CourseCode = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (arrays, trees, graphs, hash tables) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Science Hall 220", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[0], IsFeatured = true },
            new() { Id = 3, CourseCode = "CS 310", Title = "Machine Learning Fundamentals", Description = "Introduction to supervised and unsupervised learning, neural networks, and practical applications of AI in real-world systems.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", Location = "Science Hall 310", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[1], IsFeatured = true },
            new() { Id = 4, CourseCode = "CS 450", Title = "Software Engineering", Description = "Principles of software design, testing, version control, agile methodologies, and team-based project development.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", Location = "Science Hall 115", DepartmentId = 1, DepartmentName = "Computer Science", Instructor = instructors[1] },
            new() { Id = 5, CourseCode = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications in science and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Math Building 100", DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2] },
            new() { Id = 6, CourseCode = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations with computational applications.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", Location = "Math Building 110", DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2], IsFeatured = true },
            new() { Id = 7, CourseCode = "MATH 301", Title = "Abstract Algebra", Description = "Groups, rings, fields, and homomorphisms. Explores the algebraic structures underlying modern mathematics.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM", Location = "Math Building 205", DepartmentId = 2, DepartmentName = "Mathematics", Instructor = instructors[2] },
            new() { Id = 8, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Physics Lab 100", DepartmentId = 3, DepartmentName = "Physics", Instructor = instructors[3] },
            new() { Id = 9, CourseCode = "PHYS 201", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 2:00–3:20 PM", Location = "Physics Lab 200", DepartmentId = 3, DepartmentName = "Physics", Instructor = instructors[3] },
            new() { Id = 10, CourseCode = "PHYS 401", Title = "Quantum Mechanics", Description = "Wave-particle duality, Schrödinger equation, quantum states, and measurement theory.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", Location = "Physics Lab 108", DepartmentId = 3, DepartmentName = "Physics", Instructor = instructors[3], IsFeatured = true },
            new() { Id = 11, CourseCode = "ENG 101", Title = "Composition & Rhetoric", Description = "Develop effective academic writing skills through essay composition, argumentation, and critical analysis of texts.", Credits = 3, Schedule = "Tue/Thu 10:00–11:20 AM", Location = "Humanities 200", DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4] },
            new() { Id = 12, CourseCode = "ENG 250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present, exploring themes of identity, freedom, and social change.", Credits = 3, Schedule = "Mon/Wed 1:00–2:20 PM", Location = "Humanities 210", DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4] },
            new() { Id = 13, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Location = "Humanities 300", DepartmentId = 5, DepartmentName = "History", Instructor = instructors[5] },
            new() { Id = 14, CourseCode = "HIST 250", Title = "Medieval Europe", Description = "In-depth study of European society, politics, religion, and culture from the fall of Rome to the Renaissance.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", Location = "Humanities 310", DepartmentId = 5, DepartmentName = "History", Instructor = instructors[5] },
        };
    }

    public Task<List<Department>> GetDepartmentsAsync()
        => Task.FromResult(_departments.ToList());

    public Task<Department?> GetDepartmentAsync(int id)
        => Task.FromResult(_departments.FirstOrDefault(d => d.Id == id));

    public Task<List<Course>> GetCoursesAsync(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return Task.FromResult(query.ToList());
    }

    public Task<List<Course>> GetFeaturedCoursesAsync()
        => Task.FromResult(_courses.Where(c => c.IsFeatured).ToList());

    public Task<Course?> GetCourseAsync(int id)
        => Task.FromResult(_courses.FirstOrDefault(c => c.Id == id));

    public Task<bool> SubmitEnrollmentAsync(EnrollmentRequest request)
    {
        _enrollments.Add(request);
        return Task.FromResult(true);
    }
}

