            new() { Id = 11, CourseCode = "ENG 101", Title = "Composition & Rhetoric", Description = "Develop effective academic writing skills through essay composition, argumentation, and critical analysis of texts.", Credits = 3, Schedule = "Tue/Thu 10:00–11:20 AM", Location = "Humanities 200", DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4] },
            new() { Id = 12, CourseCode = "ENG 250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present, exploring themes of identity, freedom, and social change.", Credits = 3, Schedule = "Mon/Wed 1:00–2:20 PM", Location = "Humanities 210", DepartmentId = 4, DepartmentName = "English", Instructor = instructors[4] },
            new() { Id = 13, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, empires, and cultural developments from prehistory through the late medieval period.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Location = "Humanities 300", DepartmentId = 5, DepartmentName = "History", Instructor = instructors[5] },
            new() { Id = 14, CourseCode = "HIST 250", Title = "Medieval Europe", Description = "In-depth study of European society, politics, religion, and culture from the fall of Rome to the Renaissance.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", Location = "Humanities 310", DepartmentId = 5, DepartmentName = "History", Instructor = instructors[5] },
        };
    }

    public Task<List<Department>> GetDepartmentsAsync()
        => Task.FromResult(_departments.ToList());

    public Task<Department?> GetDepartmentAsync(int id)
        => Task.FromResult(_departments.FirstOrDefault(d => d.Id == id));

    public Task<List<Course>> GetCoursesAsync(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return Task.FromResult(query.ToList());
    }

    public Task<List<Course>> GetFeaturedCoursesAsync()
        => Task.FromResult(_courses.Where(c => c.IsFeatured).ToList());

    public Task<Course?> GetCourseAsync(int id)
        => Task.FromResult(_courses.FirstOrDefault(c => c.Id == id));

    public Task<bool> SubmitEnrollmentAsync(EnrollmentRequest request)
    {
        _enrollments.Add(request);
        return Task.FromResult(true);
    }
}

