arguments.file_text:
@using CourseCatalog.Models

<div class="card h-100 shadow-sm">
    <div class="card-body">
        <h5 class="card-title">
            <span class="badge bg-dark me-2">@Department.Abbreviation</span>
            @Department.Name
        </h5>
        <p class="card-text">@Department.Description</p>
        <p class="card-text text-muted small">@Department.CourseCount courses available</p>
    </div>
    <div class="card-footer bg-transparent">
        <a href="courses?departmentId=@Department.Id" class="btn btn-outline-primary btn-sm">Browse Courses</a>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Department Department { get; set; } = default!;
}

@using CourseCatalog.Models

<div class="row g-3 mb-4">
    <div class="col-md-8">
        <input type="text"
               class="form-control"
               placeholder="Search by title, course code, or instructor…"
               @bind="SearchText"
               @bind:event="oninput"
               @bind:after="OnFilterChanged" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId" @bind:after="OnFilterChanged">
            <option value="0">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
</div>

@code {
    [Parameter] public List<Department> Departments { get; set; } = new();
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public int SelectedDepartmentId { get; set; }
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }
    [Parameter] public EventCallback<int> SelectedDepartmentIdChanged { get; set; }
    [Parameter] public EventCallback OnFiltersChanged { get; set; }

    private async Task OnFilterChanged()
    {
        await SearchTextChanged.InvokeAsync(SearchText);
        await SelectedDepartmentIdChanged.InvokeAsync(SelectedDepartmentId);
        await OnFiltersChanged.InvokeAsync();
    }
}

