@page "/"
@using CourseCatalog.Models
@using CourseCatalog.Services
@using CourseCatalog.Components.Shared
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="container">
    <div class="text-center mb-5">
        <h1 class="display-4">University Course Catalog</h1>
        <p class="lead text-muted">Explore departments, discover courses, and enroll for the upcoming semester.</p>
        <div class="mt-3">
            <a href="courses" class="btn btn-primary btn-lg me-2">Browse Courses</a>
            <a href="enroll" class="btn btn-outline-success btn-lg">Enroll Now</a>
        </div>
    </div>

    <section class="mb-5">
        <h2 class="mb-3">Featured Courses</h2>
        @if (featuredCourses is null)
        {
            <p><em>Loading…</em></p>
        }
        else
        {
            <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
                @foreach (var course in featuredCourses)
                {
                    <div class="col">
                        <CourseCard Course="course" />
                    </div>
                }
            </div>
        }
    </section>

    <section>
        <h2 class="mb-3">Departments</h2>
        @if (departments is null)
        {
            <p><em>Loading…</em></p>
        }
        else
        {
            <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
                @foreach (var dept in departments)
                {
                    <div class="col">
                        <DepartmentCard Department="dept" />
                    </div>
                }
            </div>
        }
    </section>
</div>

@code {
    private List<Course>? featuredCourses;
    private List<Department>? departments;

    protected override async Task OnInitializedAsync()
    {
        featuredCourses = await Catalog.GetFeaturedCoursesAsync();
        departments = await Catalog.GetDepartmentsAsync();
    }
}

@page "/courses"
@using CourseCatalog.Models
@using CourseCatalog.Services
@using CourseCatalog.Components.Shared
@inject CatalogService Catalog
@inject NavigationManager Nav

<PageTitle>Courses – University Course Catalog</PageTitle>

<div class="container">
    <h1 class="mb-4">Courses</h1>

    <CourseFilters Departments="departments"
                   @bind-SearchText="searchText"
                   @bind-SelectedDepartmentId="selectedDepartmentId"
                   OnFiltersChanged="ApplyFilters" />

    @if (courses is null)
    {
        <p><em>Loading courses…</em></p>
    }
    else if (courses.Count == 0)
    {
        <div class="alert alert-info">No courses match your search criteria.</div>
    }
    else
    {
        <p class="text-muted mb-3">Showing @courses.Count course(s)</p>
        <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
            @foreach (var course in courses)
            {
                <div class="col">
                    <CourseCard Course="course" />
                </div>
            }
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    private List<Course>? courses;
    private List<Department> departments = new();
    private string searchText = "";
    private int selectedDepartmentId;

    protected override async Task OnInitializedAsync()
    {
        departments = await Catalog.GetDepartmentsAsync();

        if (DepartmentId.HasValue)
            selectedDepartmentId = DepartmentId.Value;

        await ApplyFilters();
    }

    private async Task ApplyFilters()
    {
        int? deptFilter = selectedDepartmentId > 0 ? selectedDepartmentId : null;
        courses = await Catalog.GetCoursesAsync(searchText, deptFilter);
    }
}

@page "/departments"
@using CourseCatalog.Models
@using CourseCatalog.Services
@using CourseCatalog.Components.Shared
@inject CatalogService Catalog

<PageTitle>Departments – University Course Catalog</PageTitle>

<div class="container">
