    @if (departments is null)
    {
        <p><em>Loading departments…</em></p>
    }
    else
    {
        <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
            @foreach (var dept in departments)
            {
                <div class="col">
                    <DepartmentCard Department="dept" />
                </div>
            }
        </div>
    }
</div>

@code {
    private List<Department>? departments;

    protected override async Task OnInitializedAsync()
    {
        departments = await Catalog.GetDepartmentsAsync();
    }
}

@page "/enroll"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject CatalogService Catalog

<PageTitle>Enroll – University Course Catalog</PageTitle>

<div class="container">
    <h1 class="mb-4">Enrollment Request</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Request Submitted!</h4>
            <p>Thank you, <strong>@model.StudentName</strong>. Your enrollment request for
               <strong>@courses.FirstOrDefault(c => c.Id == model.CourseId)?.Title</strong>
               has been received.</p>
            <hr />
            <a href="/" class="btn btn-outline-success">Return to Home</a>
            <button class="btn btn-outline-primary ms-2" @onclick="Reset">Submit Another</button>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-lg-8">
                <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                    <DataAnnotationsValidator />
                    <ValidationSummary class="text-danger mb-3" />

                    <div class="mb-3">
                        <label for="studentName" class="form-label">Full Name</label>
                        <InputText id="studentName" class="form-control" @bind-Value="model.StudentName" />
                        <ValidationMessage For="() => model.StudentName" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="studentId" class="form-label">Student ID</label>
                        <InputText id="studentId" class="form-control" placeholder="e.g., CS123456" @bind-Value="model.StudentId" />
                        <ValidationMessage For="() => model.StudentId" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="courseId" class="form-label">Course</label>
                        <InputSelect id="courseId" class="form-select" @bind-Value="model.CourseId">
                            <option value="0">— Select a course —</option>
                            @foreach (var course in courses)
                            {
                                <option value="@course.Id">@course.CourseCode – @course.Title</option>
                            }
                        </InputSelect>
                        <ValidationMessage For="() => model.CourseId" class="text-danger" />
                    </div>

                    <div class="mb-3">
                        <label for="notes" class="form-label">Notes (optional)</label>
                        <InputTextArea id="notes" class="form-control" rows="3" @bind-Value="model.Notes" />
                        <ValidationMessage For="() => model.Notes" class="text-danger" />
                    </div>

                    <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                    <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
                </EditForm>
            </div>
        </div>
    }
</div>

@code {
    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private EnrollmentRequest model = new();
    private List<Course> courses = new();
    private bool submitted;

    protected override async Task OnInitializedAsync()
    {
        courses = await Catalog.GetCoursesAsync();

        if (CourseId.HasValue)
            model.CourseId = CourseId.Value;
    }

    private async Task HandleSubmit()
    {
        await Catalog.SubmitEnrollmentAsync(model);
        submitted = true;
    }

    private void Reset()
    {
        model = new();
        submitted = false;
    }
}

